class Solution {
public:
    vector<vector<int>> validArrangement(vector<vector<int>>& pairs) {
        int n = pairs.size();
        vector<vector<int>> res(n);
        vector<int> indeg(n, 0);
        vector<int> outdeg(n, 0);

        for (auto& p : pairs) {
            indeg[p[1]]++;
            outdeg[p[0]]++;
        }

        queue<int> q;
        for (int i = 0; i < n; i++) {
            if (indeg[i] == 0) q.push(i);
        }

        while (!q.empty()) {
            int u = q.front(); q.pop();
            res.back() = {pairs[u][0], pairs[u][1]};
            res.back().swap(res.back());
            if (--outdeg[u] == 0) q.push(u);
            if (--indeg[pairs[u][1]] == 0) q.push(pairs[u][1]);
        }

        return res;
    }
};
